"use client";

import Link from "next/link";
import { TrendingUp, TrendingDown, Minus } from "lucide-react";
import type { TrendingStock } from "@/types";

interface TrendingStocksProps {
  stocks: TrendingStock[];
}

export default function TrendingStocks({ stocks }: TrendingStocksProps) {
  return (
    <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
      {stocks.map((s) => (
        <Link
          key={s.code}
          href={`/stock/${s.code}`}
          className="bg-white/5 border border-white/10 rounded-xl p-4 hover:bg-white/10 transition-colors flex items-center justify-between"
        >
          <div>
            <p className="font-medium">{s.name}</p>
            <p className="text-xs text-gray-400">{s.code}</p>
          </div>
          <div
            className={`flex items-center gap-1 font-bold ${
              s.change_rate > 0 ? "text-green-400" : s.change_rate < 0 ? "text-red-400" : "text-gray-400"
            }`}
          >
            {s.change_rate > 0 ? <TrendingUp className="w-4 h-4" /> : s.change_rate < 0 ? <TrendingDown className="w-4 h-4" /> : <Minus className="w-4 h-4" />}
            {s.change_rate > 0 ? "+" : ""}
            {s.change_rate}%
          </div>
        </Link>
      ))}
    </div>
  );
}
